# customer_impact_registry.py
# Updated whenever new enterprise customers onboard or architecture changes

COMPONENT_TO_CUSTOMERS = {
    "inference-api-us-east": [
        "acme-corp",
        "global-health-systems",
        "fintech-partner-a",
    ],
    "embedding-service": [
        "acme-corp",
        "startup-b",
    ],
    "retrieval-index-eu": [
        "eu-enterprise-c",     # GDPR jurisdiction
        "eu-enterprise-d",     # GDPR jurisdiction
    ],
}

CUSTOMER_DETAILS = {
    "acme-corp": {
        "tier": 1,
        "notification_window_hours": 2,
        "contacts": ["sre@acme.com", "account-mgr@acme.com"],
        "gdpr_jurisdiction": False,
        "hipaa": False,
        "sla_uptime": 0.999,
    },
    "eu-enterprise-c": {
        "tier": 1,
        "notification_window_hours": 2,
        "contacts": ["ops@eu-c.com"],
        "gdpr_jurisdiction": True,
        "hipaa": False,
        "sla_uptime": 0.9995,
    },
}

def get_affected_customers(affected_components: list[str]) -> list[dict]:
    affected = set()
    for component in affected_components:
        affected.update(COMPONENT_TO_CUSTOMERS.get(component, []))
    return [CUSTOMER_DETAILS[c] for c in affected if c in CUSTOMER_DETAILS]
